import argparse
import sys
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

def create_admin_client(bootstrap_servers, sasl_mechanism=None, username=None, password=None, security_protocol='PLAINTEXT'):
    """Create and return a KafkaAdminClient with appropriate security configuration."""
    try:
        client_config = {
            'bootstrap_servers': bootstrap_servers,
            'api_version': (2, 8, 0)
        }
        
        if security_protocol == 'SASL_PLAINTEXT' or security_protocol == 'SASL_SSL':
            client_config['security_protocol'] = security_protocol
            client_config['sasl_mechanism'] = sasl_mechanism or 'PLAIN'
            
            if username and password:
                client_config['sasl_plain_username'] = username
                client_config['sasl_plain_password'] = password
            else:
                raise ValueError("Username and password required for SASL authentication")
        
        return KafkaAdminClient(**client_config)
    except Exception as e:
        logger.error(f"Failed to create AdminClient: {e}")
        raise

def create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_configs=None):
    """Create a new topic with specified configuration."""
    try:
        topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs or {}
        )
        
        admin_client.create_topics([topic], validate_only=False)
        logger.info(f"Successfully created topic: {topic_name}")
        return True
    except KafkaError as e:
        logger.error(f"Failed to create topic {topic_name}: {e}")
        return False
    except Exception as e:
        logger.error(f"Unexpected error creating topic {topic_name}: {e}")
        return False

def list_topics(admin_client):
    """List all topics in the cluster."""
    try:
        topics = admin_client.list_topics()
        logger.info("Topics in cluster:")
        for topic in topics:
            logger.info(f"  {topic}")
        return topics
    except KafkaError as e:
        logger.error(f"Failed to list topics: {e}")
        return []

def describe_topic(admin_client, topic_name):
    """Describe a specific topic's configuration."""
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        configs = admin_client.describe_configs([config_resource])
        
        logger.info(f"Configuration for topic '{topic_name}':")
        for config in configs:
            for key, value in config.configs.items():
                logger.info(f"  {key}: {value}")
        return configs
    except KafkaError as e:
        logger.error(f"Failed to describe topic {topic_name}: {e}")
        return None
    except Exception as e:
        logger.error(f"Unexpected error describing topic {topic_name}: {e}")
        return None

def delete_topic(admin_client, topic_name):
    """Delete a topic from the cluster."""
    try:
        admin_client.delete_topics([topic_name])
        logger.info(f"Successfully deleted topic: {topic_name}")
        return True
    except KafkaError as e:
        logger.error(f"Failed to delete topic {topic_name}: {e}")
        return False
    except Exception as e:
        logger.error(f"Unexpected error deleting topic {topic_name}: {e}")
        return False

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (e.g., localhost:9092)')
    parser.add_argument('--action', choices=['create', 'list', 'describe', 'delete'], required=True, help='Action to perform')
    parser.add_argument('--topic', help='Topic name for create, describe, or delete actions')
    parser.add_argument('--partitions', type=int, help='Number of partitions for topic creation')
    parser.add_argument('--replication-factor', type=int, help='Replication factor for topic creation')
    parser.add_argument('--config', nargs='+', help='Topic configuration as key=value pairs')
    parser.add_argument('--sasl-mechanism', choices=['PLAIN', 'SCRAM-SHA-256', 'SCRAM-SHA-512'], help='SASL mechanism')
    parser.add_argument('--username', help='Username for SASL authentication')
    parser.add_argument('--password', help='Password for SASL authentication')
    parser.add_argument('--security-protocol', choices=['PLAINTEXT', 'SASL_PLAINTEXT', 'SASL_SSL'], default='PLAINTEXT', help='Security protocol')
    
    args = parser.parse_args()
    
    # Validate required arguments based on action
    if args.action == 'create':
        if not args.topic or args.partitions is None or args.replication_factor is None:
            logger.error("Create action requires --topic, --partitions, and --replication-factor")
            sys.exit(1)
    elif args.action in ['describe', 'delete']:
        if not args.topic:
            logger.error(f"{args.action.capitalize()} action requires --topic")
            sys.exit(1)
    
    # Parse topic configurations
    topic_configs = {}
    if args.config:
        for config in args.config:
            if '=' in config:
                key, value = config.split('=', 1)
                topic_configs[key] = value
            else:
                logger.warning(f"Invalid config format: {config}")
    
    try:
        # Create admin client
        admin_client = create_admin_client(
            bootstrap_servers=args.bootstrap_servers,
            sasl_mechanism=args.sasl_mechanism,
            username=args.username,
            password=args.password,
            security_protocol=args.security_protocol
        )
        
        # Perform action
        if args.action == 'create':
            success = create_topic(
                admin_client, 
                args.topic, 
                args.partitions, 
                args.replication_factor, 
                topic_configs
            )
            sys.exit(0 if success else 1)
        elif args.action == 'list':
            list_topics(admin_client)
        elif args.action == 'describe':
            describe_topic(admin_client, args.topic)
        elif args.action == 'delete':
            success = delete_topic(admin_client, args.topic)
            sys.exit(0 if success else 1)
            
    except Exception as e:
        logger.error(f"Script execution failed: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()